import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { productAPI } from '../services/api';
import ProductCard from '../components/products/ProductCard';
import LocalCafeIcon from '@mui/icons-material/LocalCafe';
import NatureIcon from '@mui/icons-material/Nature';
import StarIcon from '@mui/icons-material/Star';
import LocalShippingIcon from '@mui/icons-material/LocalShipping';

const categories = [
  { label: 'Green Tea', value: 'green-tea', emoji: '🍃', color: 'bg-sage-100 text-sage-700 hover:bg-sage-200' },
  { label: 'Black Tea', value: 'black-tea', emoji: '🖤', color: 'bg-amber-100 text-amber-700 hover:bg-amber-200' },
  { label: 'Matcha', value: 'matcha', emoji: '🍵', color: 'bg-lime-100 text-lime-700 hover:bg-lime-200' },
  { label: 'Herbal', value: 'herbal-tea', emoji: '🌿', color: 'bg-emerald-100 text-emerald-700 hover:bg-emerald-200' },
  { label: 'Oolong', value: 'oolong-tea', emoji: '🌸', color: 'bg-orange-100 text-orange-700 hover:bg-orange-200' },
  { label: 'Chai', value: 'chai', emoji: '🌶️', color: 'bg-red-100 text-red-700 hover:bg-red-200' },
];

const features = [
  { icon: <NatureIcon />, title: 'Single Origin', desc: 'Teas sourced directly from origin gardens across Asia and beyond.' },
  { icon: <StarIcon />, title: 'Premium Quality', desc: 'Every tea is hand-selected and tested by our expert tea masters.' },
  { icon: <LocalShippingIcon />, title: 'Free Shipping', desc: 'Complimentary shipping on all orders over $50.' },
  { icon: <LocalCafeIcon />, title: 'Expert Guidance', desc: 'Brewing guides and personalised recommendations included.' },
];

const HomePage = () => {
  const [featured, setFeatured] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    productAPI.getAll({ featured: true, limit: 4 })
      .then(({ data }) => setFeatured(data.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  return (
    <div>
      {/* Hero */}
      <section className="relative overflow-hidden bg-tea-pattern">
        <div className="absolute inset-0 bg-gradient-to-br from-tea-900 via-tea-800 to-tea-700 opacity-95" />
        <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-24 lg:py-36">
          <div className="max-w-2xl">
            <span className="inline-block badge bg-tea-500/30 text-tea-200 mb-4 px-3 py-1 text-xs uppercase tracking-widest">
              Direct from Origin
            </span>
            <h1 className="font-display text-5xl lg:text-7xl font-bold text-white leading-tight mb-6">
              Tea as it was<br />
              <em className="text-tea-300">meant to be.</em>
            </h1>
            <p className="text-tea-200 text-lg leading-relaxed mb-8 max-w-lg">
              Rare teas sourced from the world's finest gardens — from the misty hills of Darjeeling to the ancient forests of Yunnan.
            </p>
            <div className="flex flex-col sm:flex-row gap-3">
              <Link to="/shop" className="btn-primary text-base py-3 px-8 text-center">
                Explore Collection
              </Link>
              <Link to="/shop?featured=true" className="btn-secondary text-base py-3 px-8 text-center border-tea-300 text-tea-200 hover:bg-tea-700">
                Featured Teas
              </Link>
            </div>
          </div>
        </div>
        {/* Decorative leaf */}
        <div className="absolute right-0 top-0 h-full w-1/2 flex items-center justify-center opacity-10 pointer-events-none">
          <span className="text-[20rem] select-none">🍃</span>
        </div>
      </section>

      {/* Categories */}
      <section className="py-16 bg-white">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <h2 className="font-display text-3xl text-tea-900 text-center mb-10">Browse by Type</h2>
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-3">
            {categories.map((cat) => (
              <Link
                key={cat.value}
                to={`/shop?category=${cat.value}`}
                className={`flex flex-col items-center gap-2 py-5 px-3 rounded-2xl font-medium text-sm transition-all duration-200 hover:-translate-y-0.5 hover:shadow-sm ${cat.color}`}
              >
                <span className="text-3xl">{cat.emoji}</span>
                <span>{cat.label}</span>
              </Link>
            ))}
          </div>
        </div>
      </section>

      {/* Featured Products */}
      <section className="py-16 bg-cream">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between mb-10">
            <h2 className="font-display text-3xl text-tea-900">Featured Teas</h2>
            <Link to="/shop?featured=true" className="btn-ghost text-tea-700 text-sm">View all →</Link>
          </div>
          {loading ? (
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-5">
              {[...Array(4)].map((_, i) => (
                <div key={i} className="card animate-pulse">
                  <div className="aspect-square bg-tea-100" />
                  <div className="p-4 space-y-2">
                    <div className="h-3 bg-tea-100 rounded w-1/3" />
                    <div className="h-4 bg-tea-100 rounded w-3/4" />
                    <div className="h-3 bg-tea-100 rounded w-1/2" />
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-5">
              {featured.map((product) => <ProductCard key={product._id} product={product} />)}
            </div>
          )}
        </div>
      </section>

      {/* Features */}
      <section className="py-16 bg-tea-900">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
            {features.map((f, i) => (
              <div key={i} className="text-center">
                <div className="w-12 h-12 bg-tea-700 rounded-xl flex items-center justify-center text-tea-300 mx-auto mb-4">
                  {f.icon}
                </div>
                <h3 className="font-display text-white font-medium mb-2">{f.title}</h3>
                <p className="text-tea-300 text-sm leading-relaxed">{f.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* CTA */}
      <section className="py-20 bg-sage-50">
        <div className="max-w-2xl mx-auto text-center px-4">
          <h2 className="font-display text-4xl text-tea-900 mb-4">Start Your Tea Journey</h2>
          <p className="text-gray-600 leading-relaxed mb-8">
            Join thousands of tea lovers discovering the world's finest teas. New arrivals added weekly.
          </p>
          <Link to="/register" className="btn-primary text-base py-3 px-10">Create Your Account</Link>
        </div>
      </section>
    </div>
  );
};

export default HomePage;
